class MajorityChecker {
public:
    vector<int> count;
    MajorityChecker(vector<int>& arr) {
        count.resize(100005, 0);
        for (int num : arr) {
            count[num]++;
        }
    }

    int query(int left, int right, int threshold) {
        int maxCount = 0;
        int majority = -1;
        for (int i = left; i <= right; i++) {
            int num = arr[i];
            if (count[num] > maxCount) {
                maxCount = count[num];
                majority = num;
            }
        }
        return (maxCount >= threshold) ? majority : -1;
    }
private:
    vector<int> arr;
};
